export function toBase64String(value: string): string {
  let b64 = '';
  const encoded = utf8Encode(value);
  for (let i = 0; i < encoded.length; ) {
    const i1 = encoded[i++];
    const i2 = i < encoded.length ? encoded[i++] : null;
    const i3 = i < encoded.length ? encoded[i++] : null;
    b64 += toBase64Digit(i1 >> 2);
    b64 += toBase64Digit(((i1 & 3) << 4) | (i2 === null ? 0 : i2 >> 4));
    b64 += i2 === null ? '=' : toBase64Digit(((i2 & 15) << 2) | (i3 === null ? 0 : i3 >> 6));
    b64 += i2 === null || i3 === null ? '=' : toBase64Digit(i3 & 63);
  }

  return b64;
}

export function d3InjectorTreeNodeModifier(d3Node: SvgD3Node<InjectorTreeNode>) {
  d3Node
    .attr('class', (node: InjectorTreeD3Node) => {
      return [d3Node.attr('class'), INJECTOR_TYPE_CLASS_MAP.get(node.data.injector.type) ?? '']
        .filter((c) => !!c)
        .join(' ');
    })
    .attr('hidden', (node: InjectorTreeD3Node) => (node.data.injector.id === 'N/A' ? 'true' : null))
    .attr('data-id', (node: InjectorTreeD3Node) => {
      return node.data.injector.id;
    })
    .attr('data-component-id', (node: InjectorTreeD3Node) => {
      if (node.data.injector.type === 'element') {
        const injector = node.data.injector;
        return injector.node?.component?.id ?? -1;
      }
      return -1;
    });
}

export function i18nCreateOpCodesToString(
  this: I18nCreateOpCodes | void,
  opcodes?: I18nCreateOpCodes,
): string[] {
  const createOpCodes: I18nCreateOpCodes = opcodes || (Array.isArray(this) ? this : ([] as any));
  let lines: string[] = [];
  for (let i = 0; i < createOpCodes.length; i++) {
    const opCode = createOpCodes[i++] as any;
    const text = createOpCodes[i] as string;
    const isComment = (opCode & I18nCreateOpCode.COMMENT) === I18nCreateOpCode.COMMENT;
    const appendNow =
      (opCode & I18nCreateOpCode.APPEND_EAGERLY) === I18nCreateOpCode.APPEND_EAGERLY;
    const index = opCode >>> I18nCreateOpCode.SHIFT;
    lines.push(
      `lView[${index}] = document.${isComment ? 'createComment' : 'createText'}(${JSON.stringify(
        text,
      )});`,
    );
    if (appendNow) {
      lines.push(`parent.appendChild(lView[${index}]);`);
    }
  }
  return lines;
}

export async function generateZip(files: FileAndContent[]): Promise<Uint8Array> {
  if (zip === undefined || strToU8 === undefined) {
    const fflate = require('fflate');
    zip = fflate.zip;
    strToU8 = fflate.strToU8;
  }
  const filesObj: Record<string, Uint8Array> = {};
  files.forEach(({path, content}) => {
    filesObj[path] = typeof content === 'string' ? strToU8(content) : content;
  });

  return new Promise((resolve, reject) => {
    zip(filesObj, (err: any, data: any) => {
      if (err) {
        reject(err);
      } else {
        resolve(data);
      }
    });
  });
}

() => {
  if (this.activeDestination()) {
    return STAND;
  }

  const direction = this.walkingDirection();
  const frame = this.walkFrame();
  const animationFrame = Math.floor(frame / ANIMATION_SPEED) % 2;
  switch (direction) {
    case 'left':
      return animationFrame === 0 ? WALK_LEFT_1 : WALK_LEFT_2;
    case 'right':
      return animationFrame === 0 ? WALK_RIGHT_1 : WALK_RIGHT_2;
    case 'up':
      return animationFrame === 0 ? WALK_UP_1 : WALK_UP_2;
    case 'down':
      return animationFrame === 0 ? WALK_DOWN_1 : WALK_DOWN_2;
    default:
      return STAND;
  }
}

