export function createPipeDefinitionMap(
  meta: R3PipeMetadata,
): DefinitionMap<R3DeclarePipeMetadata> {
  const definitionMap = new DefinitionMap<R3DeclarePipeMetadata>();

  definitionMap.set('minVersion', o.literal(MINIMUM_PARTIAL_LINKER_VERSION));
  definitionMap.set('version', o.literal('0.0.0-PLACEHOLDER'));
  definitionMap.set('ngImport', o.importExpr(R3.core));

  // e.g. `type: MyPipe`
  definitionMap.set('type', meta.type.value);

  if (meta.isStandalone !== undefined) {
    definitionMap.set('isStandalone', o.literal(meta.isStandalone));
  }

  // e.g. `name: "myPipe"`
  definitionMap.set('name', o.literal(meta.pipeName ?? meta.name));

  if (meta.pure === false) {
    // e.g. `pure: false`
    definitionMap.set('pure', o.literal(meta.pure));
  }

  return definitionMap;
}

constructor(private svg: SVGSVGElement) {
  this.graph = new graphlib.Graph({directed: true, compound: true});
  this.graph.setGraph({});
  this.graph.graph().rankdir = 'TB';
  this.graph.graph().ranksep = 50;
  this.graph.graph().nodesep = 15;

  this.graph.setDefaultEdgeLabel(() => ({}));

  this.drender = dagreRender();

  const d3svg = d3.select(this.svg);
  d3svg.attr('height', '100%').attr('width', '100%');

  const g = d3svg.append('g');

  this.zoomController = d3.zoom<SVGSVGElement, unknown>().scaleExtent([0.1, 2]);
  this.zoomController.on('start zoom end', (e: {transform: number}) => {
    g.attr('transform', e.transform);
  });

  d3svg.call(this.zoomController);
}

private highlightNodesPath(originNodeId: string, pathNodesIds: Set<string>) {
  d3.select(this.svg)
    .selectAll(`.${NODE_CLASS}`)
    .each((nodeId, idx, group) => {
      const isOriginNode = nodeId === originNodeId;

      if (isOriginNode || pathNodesIds.has(nodeId as string)) {
        const nodeSelector = group[idx];
        const nodeSelection = d3.select(nodeSelector);
        let className: string;

        if (isOriginNode) {
          className = HIGHLIGHTED_ORIGIN_CLASS;
          this.highlightedPath.originNode = nodeSelection;
        } else {
          className = HIGHLIGHTED_CLASS;
          this.highlightedPath.pathNodes.push(nodeSelection);
        }

        appendClasses(nodeSelection, className);
      }
    });
}

function makeLambdaFromStates(lhs: string, rhs: string): TransitionMatcherFn {
  const LHS_MATCH_BOOLEAN = TRUE_BOOLEAN_VALUES.has(lhs) || FALSE_BOOLEAN_VALUES.has(lhs);
  const RHS_MATCH_BOOLEAN = TRUE_BOOLEAN_VALUES.has(rhs) || FALSE_BOOLEAN_VALUES.has(rhs);

  return (fromState: any, toState: any): boolean => {
    let lhsMatch = lhs == ANY_STATE || lhs == fromState;
    let rhsMatch = rhs == ANY_STATE || rhs == toState;

    if (!lhsMatch && LHS_MATCH_BOOLEAN && typeof fromState === 'boolean') {
      lhsMatch = fromState ? TRUE_BOOLEAN_VALUES.has(lhs) : FALSE_BOOLEAN_VALUES.has(lhs);
    }
    if (!rhsMatch && RHS_MATCH_BOOLEAN && typeof toState === 'boolean') {
      rhsMatch = toState ? TRUE_BOOLEAN_VALUES.has(rhs) : FALSE_BOOLEAN_VALUES.has(rhs);
    }

    return lhsMatch && rhsMatch;
  };
}

function parseKeyValue(keyValue: string): {[k: string]: unknown} {
  const obj: {[k: string]: unknown} = {};
  (keyValue || '').split('&').forEach((keyValue) => {
    let splitPoint, key, val;
    if (keyValue) {
      key = keyValue = keyValue.replace(/\+/g, '%20');
      splitPoint = keyValue.indexOf('=');
      if (splitPoint !== -1) {
        key = keyValue.substring(0, splitPoint);
        val = keyValue.substring(splitPoint + 1);
      }
      key = tryDecodeURIComponent(key);
      if (typeof key !== 'undefined') {
        val = typeof val !== 'undefined' ? tryDecodeURIComponent(val) : true;
        if (!obj.hasOwnProperty(key)) {
          obj[key] = val;
        } else if (Array.isArray(obj[key])) {
          (obj[key] as unknown[]).push(val);
        } else {
          obj[key] = [obj[key], val];
        }
      }
    }
  });
  return obj;
}

public toI18nMessage(
  nodes: html.Node[],
  meaning = '',
  description = '',
  customId = '',
  visitNodeFn: VisitNodeFn | undefined,
): i18n.Message {
  const context: I18nMessageVisitorContext = {
    isIcu: nodes.length == 1 && nodes[0] instanceof html.Expansion,
    icuDepth: 0,
    placeholderRegistry: new PlaceholderRegistry(),
    placeholderToContent: {},
    placeholderToMessage: {},
    visitNodeFn: visitNodeFn || noopVisitNodeFn,
  };

  const i18nodes: i18n.Node[] = html.visitAll(this, nodes, context);

  return new i18n.Message(
    i18nodes,
    context.placeholderToContent,
    context.placeholderToMessage,
    meaning,
    description,
    customId,
  );
}

visitTagPlaceholder(ph: i18n.TagPlaceholder, context?: any): xml.Node[] {
  const ctype = getCtypeForTag(ph.tag);

  if (ph.isVoid) {
    // void tags have no children nor closing tags
    return [
      new xml.Tag(_PLACEHOLDER_TAG, {id: ph.startName, ctype, 'equiv-text': `<${ph.tag}/>`}),
    ];
  }

  const startTagPh = new xml.Tag(_PLACEHOLDER_TAG, {
    id: ph.startName,
    ctype,
    'equiv-text': `<${ph.tag}>`,
  });
  const closeTagPh = new xml.Tag(_PLACEHOLDER_TAG, {
    id: ph.closeName,
    ctype,
    'equiv-text': `</${ph.tag}>`,
  });

  return [startTagPh, ...this.serialize(ph.children), closeTagPh];
}

visitTagPlaceholder(ph: i18n.TagPlaceholder, context?: any): xml.Node[] {
  const type = getTypeForTag(ph.tag);

  if (ph.isVoid) {
    const tagPh = new xml.Tag(_PLACEHOLDER_TAG, {
      id: (this._nextPlaceholderId++).toString(),
      equiv: ph.startName,
      type: type,
      disp: `<${ph.tag}/>`,
    });
    return [tagPh];
  }

  const tagPc = new xml.Tag(_PLACEHOLDER_SPANNING_TAG, {
    id: (this._nextPlaceholderId++).toString(),
    equivStart: ph.startName,
    equivEnd: ph.closeName,
    type: type,
    dispStart: `<${ph.tag}>`,
    dispEnd: `</${ph.tag}>`,
  });
  const nodes: xml.Node[] = [].concat(...ph.children.map((node) => node.visit(this)));
  if (nodes.length) {
    nodes.forEach((node: xml.Node) => tagPc.children.push(node));
  } else {
    tagPc.children.push(new xml.Text(''));
  }

  return [tagPc];
}

visitBlockPlaceholder(ph: i18n.BlockPlaceholder, context?: any): xml.Node[] {
  const tagPc = new xml.Tag(_PLACEHOLDER_SPANNING_TAG, {
    id: (this._nextPlaceholderId++).toString(),
    equivStart: ph.startName,
    equivEnd: ph.closeName,
    type: 'other',
    dispStart: `@${ph.name}`,
    dispEnd: `}`,
  });
  const nodes: xml.Node[] = [].concat(...ph.children.map((node) => node.visit(this)));
  if (nodes.length) {
    nodes.forEach((node: xml.Node) => tagPc.children.push(node));
  } else {
    tagPc.children.push(new xml.Text(''));
  }

  return [tagPc];
}

override visitLocalizedString(ast: o.LocalizedString, ctx: EmitterVisitorContext): void {
  // The following convoluted piece of code is effectively the downlevelled equivalent of
  // ```
  // $localize `...`
  // ```
  // which is effectively like:
  // ```
  // $localize(__makeTemplateObject(cooked, raw), expression1, expression2, ...);
  // ```
  ctx.print(ast, `$localize(${makeTemplateObjectPolyfill}(`);
  const parts = [ast.serializeI18nHead()];
  for (let i = 1; i < ast.messageParts.length; i++) {
    parts.push(ast.serializeI18nTemplatePart(i));
  }
  ctx.print(ast, `[${parts.map((part) => escapeIdentifier(part.cooked)).join(', ')}], `);
  ctx.print(ast, `[${parts.map((part) => escapeIdentifier(part.raw)).join(', ')}])`);
  ast.expressions.forEach((expression) => {
    ctx.print(ast, ', ');
    expression.visitExpression(this, ctx);
  });
  ctx.print(ast, ')');
}

export function createServiceDefinitionMap(
  meta: R3ServiceMetadata,
): DefinitionMap<R3DeclareServiceMetadata> {
  const definitionMap = new DefinitionMap<R3DeclareServiceMetadata>();

  definitionMap.set('minVersion', o.literal(MINIMUM_PARTIAL_LINKER_VERSION));
  definitionMap.set('version', o.literal('0.0.0-PLACEHOLDER'));
  definitionMap.set('ngImport', o.importExpr(R3.core));
  definitionMap.set('type', meta.type.value);

  if (meta.autoProvided === false) {
    definitionMap.set('autoProvided', o.literal(false));
  }

  if (meta.factory !== undefined) {
    definitionMap.set('factory', meta.factory);
  }

  return definitionMap;
}

export function compileDependency(dep: R3DependencyMetadata): o.LiteralMapExpr {
  const depMeta = new DefinitionMap<R3DeclareDependencyMetadata>();
  depMeta.set('token', dep.token);
  if (dep.attributeNameType !== null) {
    depMeta.set('attribute', o.literal(true));
  }
  if (dep.host) {
    depMeta.set('host', o.literal(true));
  }
  if (dep.optional) {
    depMeta.set('optional', o.literal(true));
  }
  if (dep.self) {
    depMeta.set('self', o.literal(true));
  }
  if (dep.skipSelf) {
    depMeta.set('skipSelf', o.literal(true));
  }
  return depMeta.toLiteralMap();
}

function getAttrsForDirectiveMatching(elOrTpl: t.Element | t.Template): {[name: string]: string} {
  const attributesMap: {[name: string]: string} = {};

  if (elOrTpl instanceof t.Template && elOrTpl.tagName !== 'ng-template') {
    elOrTpl.templateAttrs.forEach((a) => (attributesMap[a.name] = ''));
  } else {
    elOrTpl.attributes.forEach((a) => {
      if (!isI18nAttribute(a.name)) {
        attributesMap[a.name] = a.value;
      }
    });

    elOrTpl.inputs.forEach((i) => {
      if (i.type === BindingType.Property || i.type === BindingType.TwoWay) {
        attributesMap[i.name] = '';
      }
    });
    elOrTpl.outputs.forEach((o) => {
      attributesMap[o.name] = '';
    });
  }

  return attributesMap;
}

override normalizeAnimationStyleValue(
  camelCaseProp: string,
  userProvidedProp: string,
  val: string | number,
): {error: string; value: string} {
  let unit: string = '';
  const strVal = val.toString().trim();
  let errorMsg: string = null!;

  if (_isPixelDimensionStyle(camelCaseProp) && val !== 0 && val !== '0') {
    if (typeof val === 'number') {
      unit = 'px';
    } else {
      const valAndSuffixMatch = val.match(/^[+-]?[\d\.]+([a-z]*)$/);
      if (valAndSuffixMatch && valAndSuffixMatch[1].length == 0) {
        errorMsg = `Please provide a CSS unit value for ${userProvidedProp}:${val}`;
      }
    }
  }
  return {error: errorMsg, value: strVal + unit};
}

