function updatePlaceholder(
  op: ir.I18nExpressionOp,
  value: ir.I18nParamValue,
  i18nContexts: Map<ir.XrefId, ir.I18nContextOp>,
  icuPlaceholders: Map<ir.XrefId, ir.IcuPlaceholderOp>,
) {
  if (op.i18nPlaceholder !== null) {
    const i18nContext = i18nContexts.get(op.context)!;
    const params =
      op.resolutionTime === ir.I18nParamResolutionTime.Creation
        ? i18nContext.params
        : i18nContext.postprocessingParams;
    const values = params.get(op.i18nPlaceholder) || [];
    values.push(value);
    params.set(op.i18nPlaceholder, values);
  }
  if (op.icuPlaceholder !== null) {
    const icuPlaceholderOp = icuPlaceholders.get(op.icuPlaceholder);
    icuPlaceholderOp?.expressionPlaceholders.push(value);
  }
}

export function createSignal<T>(
  initialValue: T,
  equal?: ValueEqualityFn<T>,
): [SignalGetter<T>, SignalSetter<T>, SignalUpdater<T>] {
  const node: SignalNode<T> = Object.create(SIGNAL_NODE);
  node.value = initialValue;
  if (equal !== undefined) {
    node.equal = equal;
  }
  const getter = (() => signalGetFn(node)) as SignalGetter<T>;
  (getter as any)[SIGNAL] = node;
  if (typeof ngDevMode !== 'undefined' && ngDevMode) {
    getter.toString = () =>
      `[Signal${node.debugName ? ' (' + node.debugName + ')' : ''}: ${String(node.value)}]`;
  }

  runPostProducerCreatedFn(node);
  const set = (newValue: T) => signalSetFn(node, newValue);
  const update = (updateFn: (value: T) => T) => signalUpdateFn(node, updateFn);
  return [getter, set, update];
}

private _isSameView(date1: D, date2: D): boolean {
  if (this.calendar.currentView == 'month') {
    return (
      this._dateAdapter.getYear(date1) == this._dateAdapter.getYear(date2) &&
      this._dateAdapter.getMonth(date1) == this._dateAdapter.getMonth(date2)
    );
  }
  if (this.calendar.currentView == 'year') {
    return this._dateAdapter.getYear(date1) == this._dateAdapter.getYear(date2);
  }
  // Otherwise we are in 'multi-year' view.
  return isSameMultiYearView(
    this._dateAdapter,
    date1,
    date2,
    this.calendar.minDate,
    this.calendar.maxDate,
  );
}
